@app.route("/first-run", methods=["GET", "POST"])
@login_required
def first_run():
    if session.get("is_admin") == 1:
        return redirect(url_for("dashboard"))
    db = get_db()
    uid = session["user_id"]
    user = db.execute(
        """
        SELECT id, username, display_name, screen_choice, character_choice, work_mode, setup_completed
        FROM users WHERE id = ?
        """,
        (uid,),
    ).fetchone()
    if not user:
        flash("Пользователь не найден.")
        return redirect(url_for("logout"))
    if int(user["setup_completed"] or 0) == 1:
        return redirect(url_for("dashboard"))

    allowed_screens = {s[0] for s in SCREEN_OPTIONS}

    if request.method == "POST":
        display_name = (request.form.get("display_name") or "").strip()
        screen_choice = (request.form.get("screen_choice") or "diary").strip()
        character_choice = (request.form.get("character_choice") or "male").strip()
        work_mode = (request.form.get("work_mode") or "auto").strip()

        if not display_name:
            flash("Введите имя пользователя для учёта.")
            return render_template(
                "first_run.html",
                screens=SCREEN_OPTIONS,
                display_name=display_name,
                screen_choice=screen_choice if screen_choice in allowed_screens else "diary",
                character_choice=character_choice if character_choice in ("male", "female") else "male",
                work_mode=work_mode if work_mode in ("auto", "manual") else "auto",
            )

        dup = db.execute(
            """
            SELECT id FROM users
            WHERE id != ? AND (
                lower(trim(display_name)) = lower(trim(?))
                OR lower(trim(username)) = lower(trim(?))
            )
            """,
            (uid, display_name, display_name),
        ).fetchone()
        if dup:
            flash("Такое имя уже занято. Выберите другое (имена не должны повторяться).")
            return render_template(
                "first_run.html",
                screens=SCREEN_OPTIONS,
                display_name=display_name,
                screen_choice=screen_choice if screen_choice in allowed_screens else "diary",
                character_choice=character_choice if character_choice in ("male", "female") else "male",
                work_mode=work_mode if work_mode in ("auto", "manual") else "auto",
            )

        if screen_choice not in allowed_screens:
            screen_choice = "diary"
        if character_choice not in ("male", "female"):
            character_choice = "male"
        if work_mode not in ("auto", "manual"):
            work_mode = "auto"

        db.execute(
            """
            UPDATE users SET display_name = ?, screen_choice = ?, character_choice = ?,
                work_mode = ?, setup_completed = 1
            WHERE id = ?
            """,
            (display_name, screen_choice, character_choice, work_mode, uid),
        )
        db.commit()
        updated = db.execute(
            """
            SELECT id, username, display_name, screen_choice, character_choice, work_mode, setup_completed, is_admin
            FROM users WHERE id = ?
            """,
            (uid,),
        ).fetchone()
        load_user_profile_into_session(updated)
        flash("Настройки сохранены. Можно приступать к занятиям.")
        return redirect(url_for("dashboard"))

    return render_template(
