        work_mode = profile["work_mode"] or "auto"
        screen_choice = profile["screen_choice"] or "diary"
        character_choice = profile["character_choice"] or "male"
        auto_idx = int(profile["auto_queue_index"] or 0)
        session["work_mode"] = work_mode
        session["screen_choice"] = screen_choice
        session["character_choice"] = character_choice

    auto_seq = get_auto_sequence(db)
    auto_total = len(auto_seq)
    auto_current = None
    if auto_total:
        auto_idx = max(0, min(auto_idx, auto_total - 1))
        auto_current = auto_seq[auto_idx]

    summary = db.execute(
        """
        SELECT COUNT(*) AS total,
               SUM(CASE WHEN completed = 1 THEN 1 ELSE 0 END) AS done,
               ROUND(AVG(score), 1) AS avg_score
        FROM progress
        WHERE user_id = ?
        """,
        (uid,),
    ).fetchone()
    return render_template(
        "dashboard.html",
