def work_auto_advance():
    if needs_first_run_setup():
        return redirect(url_for("first_run"))
    db = get_db()
    seq = get_auto_sequence(db)
    if not seq:
        flash("Каталог упражнений пуст.")
        return redirect(url_for("dashboard"))
    row = db.execute(
        "SELECT auto_queue_index FROM users WHERE id = ?", (session["user_id"],)
