@app.route("/legacy-gt/<path:rel_path>")
@login_required
def legacy_gt(rel_path):
    """Безопасная раздача только GT/Music/*.wav и GT/Pictures/*.bmp."""
    rel_norm = rel_path.replace("\\", "/").strip("/")
    if not rel_norm or ".." in rel_norm.split("/"):
        abort(404)
    top = rel_norm.split("/", 1)[0]
    if top not in ("Music", "Pictures"):
        abort(404)
    suf = Path(rel_norm).suffix.lower()
    if suf not in (".wav", ".bmp"):
        abort(404)
    base = LEGACY_GT.resolve()
    target = (base / rel_norm).resolve()
    try:
        target.relative_to(base)
    except ValueError:
        abort(404)
    if not target.is_file():
        abort(404)
    mimetype = "audio/wav" if suf == ".wav" else "image/bmp"
    return send_file(target, mimetype=mimetype, conditional=True)


