{% block content %}
<style>
  .d11-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 10px; align-items: start; }
  .d11-tile { border: 1px solid #c2cdd6; padding: 6px; text-align: center; background: #fafafa; }
  .d11-tile a { display: block; }
  .d11-tile img { width: 100%; height: auto; max-height: 120px; object-fit: contain; vertical-align: middle; }
  .d11-tile .cap { font-size: 9pt; margin-top: 4px; color: #374151; }
  .d11-stage-wrap { border: 1px solid #c2cdd6; background: #000; padding: 8px; text-align: center; position: relative; }
  .d11-stage-wrap img { max-width: 100%; max-height: min(70vh, 640px); height: auto; }
  .d11-toolbar { margin: 10px 0; display: flex; flex-wrap: wrap; gap: 8px; align-items: center; }
  .d11-toolbar button { width: auto; margin: 0; padding: 8px 14px; font-size: 9pt; }
  .d11-tracks { display: flex; flex-wrap: wrap; gap: 6px; margin-top: 8px; }
  .d11-tracks button { width: auto; margin: 0; padding: 6px 10px; font-size: 9pt; background: #1e3a5f; }
  .d11-tracks button:disabled { opacity: 0.45; cursor: not-allowed; }
  audio#d11-audio { width: 100%; max-width: 560px; margin-top: 10px; }
  .d11-help { max-height: 320px; overflow: auto; border: 1px solid #dee3e7; padding: 10px; background: #fafafa; font-size: 10pt; text-align: justify; }
  .d11-help ul { margin: 6px 0 6px 20px; }
</style>

<h2>{{ module["title"] }} (D11)</h2>
<p class="muted">{{ module["description"] }}</p>

{% if not legacy_ok %}
<div class="flash">Папка <code>GT</code> не найдена рядом с приложением. Установите оригинальные каталоги <code>GT/Pictures</code> и <code>GT/Music</code> (как в исходной программе), чтобы отображались картинки и звуки T01–T12.</div>
{% elif not pictures %}
<div class="flash">В <code>GT/Pictures</code> нет файлов изображений (.bmp, кроме миниатюр *_m.bmp). Скопируйте картинки из установки «Глобал Т.Э.М.П.».</div>
{% endif %}

{% if pick %}
<p><a href="{{ url_for('d11_module', module_id=module.id) }}">← Вернуться к выбору картинки</a></p>
<div id="d11-stage" class="d11-stage-wrap">
  <img src="{{ url_for('legacy_gt', rel_path='Pictures/' + pick) }}" alt="{{ pick }}">
</div>
<div class="d11-toolbar">
  <button type="button" id="d11-fullscreen">Полный экран (как в оригинале)</button>
  <span class="muted" style="font-size:9pt;">Рекомендуемый трек для этого тайла: T{{ '%02d'|format(suggested_track_num) }} {% if suggested_track_num == 1 %}(с голосом){% endif %}</span>
</div>
{% if primary_track_url %}
<audio id="d11-audio" controls preload="metadata" src="{{ primary_track_url }}"></audio>
{% else %}
<p class="muted">Файл мелодии T{{ '%02d'|format(suggested_track_num) }} не найден в <code>GT/Music</code>. Выберите трек ниже.</p>
<audio id="d11-audio" controls preload="metadata"></audio>
{% endif %}
<p class="muted" style="font-size:9pt;">Все мелодии (переключение вручную — как при выборе «только мелодия» для других картинок):</p>
<div class="d11-tracks" id="d11-track-buttons">
  {% for t in tracks %}
  <button type="button" {% if not t.url %}disabled{% endif %} data-url="{{ t.url or '' }}">{{ t.code }} · {{ t.duration }}</button>
