    </tr>
    {% endfor %}
  </table>
</div>

<div class="card">
  <h3>Полный текст из руководства</h3>
  <div class="d11-help">{% include "d11_help_fragment.html" %}</div>
</div>

<div class="card">
  <h3>Отметка выполнения</h3>
  <form method="post">
    <button type="submit">Я завершил сессию А-Тренинга</button>
  </form>
</div>

<script>
(function () {
  var audio = document.getElementById("d11-audio");
  var bar = document.getElementById("d11-track-buttons");
  var stage = document.getElementById("d11-stage");
  var fsBtn = document.getElementById("d11-fullscreen");
  if (bar && audio) {
    bar.addEventListener("click", function (e) {
      var btn = e.target.closest("button");
      if (!btn || btn.disabled) return;
      var u = btn.getAttribute("data-url");
      if (!u) return;
      audio.src = u;
      audio.play().catch(function () {});
    });
  }
  if (fsBtn && stage) {
    fsBtn.addEventListener("click", function () {
      var el = stage;
      if (!document.fullscreenElement) {
        (el.requestFullscreen || el.webkitRequestFullscreen || el.msRequestFullscreen).call(el);
      } else {
        (document.exitFullscreen || document.webkitExitFullscreen || document.msExitFullscreen).call(document);
      }
    });
  }
})();
</script>
{% endblock %}

