def resolve_legacy_gt_path() -> Path:
    """Корень установки «Глобал Т.Э.М.П.» с подпапками Pictures и Music.

    Порядок: переменная LEGACY_GT_ROOT → web-app/GT (если есть) → ../GT рядом с web-app.
    """
    env = os.environ.get("LEGACY_GT_ROOT", "").strip()
    if env:
        return Path(env).expanduser().resolve()
    inside = BASE_DIR / "GT"
    if inside.is_dir():
        return inside.resolve()
    return (BASE_DIR.parent / "GT").resolve()


LEGACY_GT = resolve_legacy_gt_path()


def _legacy_subdir_ci(name: str):
    """Подкаталог GT (Pictures, Music) без учёта регистра имени папки."""
    if not LEGACY_GT.is_dir():
        return None
    want = name.lower()
    for ch in LEGACY_GT.iterdir():
        if ch.is_dir() and ch.name.lower() == want:
            return ch
    return None


def legacy_pictures_dir() -> Path | None:
    d = _legacy_subdir_ci("Pictures")
    return d if d and d.is_dir() else None


def legacy_music_dir() -> Path | None:
    d = _legacy_subdir_ci("Music")
    return d if d and d.is_dir() else None


def _resolve_legacy_media_file(rel_norm: str) -> Path | None:
    """Файл под LEGACY_GT; при несовпадении регистра имён (Windows/Linux) — подбор по имени."""
    base = LEGACY_GT.resolve()
    if not base.is_dir():
        return None
    direct = (base / rel_norm).resolve()
    try:
        direct.relative_to(base)
    except ValueError:
        return None
    if direct.is_file():
        return direct
    segs = rel_norm.split("/")
    if len(segs) < 2:
        return None
    top, fname = segs[0], segs[-1]
    sub = _legacy_subdir_ci("Pictures" if top.lower() == "pictures" else "Music")
    if not sub or top.lower() not in ("pictures", "music"):
        return None
    for f in sub.iterdir():
        if f.is_file() and f.name.lower() == fname.lower():
            try:
                f.resolve().relative_to(base)
            except ValueError:
                continue
            return f
    return None


def list_a_training_pictures():
    """Имена .bmp из GT/Pictures без миниатюр *_m.bmp (как в оригинале)."""
    pic_dir = legacy_pictures_dir()
