        return []
    out = []
    for p in sorted(pic_dir.iterdir(), key=lambda x: x.name.lower()):
        if not p.is_file():
            continue
        if p.suffix.lower() != ".bmp":
            continue
        if p.name.lower().endswith("_m.bmp"):
            continue
        out.append(p.name)
    return out


def music_track_relpath(track_num: int):
    """Относительный путь под GT к файлу Tnn (любой регистр расширения .wav)."""
    n = max(1, min(12, int(track_num)))
    folder = legacy_music_dir()
    if not folder:
        return None
    prefix = f"T{n:02d}"
    for cand in (f"{prefix}.WAV", f"{prefix}.wav", f"{prefix}.Wav"):
        p = folder / cand
        if p.is_file():
            return f"Music/{p.name}"
    for p in folder.iterdir():
        if not p.is_file():
            continue
        if p.stem.upper() == prefix.upper() and p.suffix.lower() == ".wav":
            return f"Music/{p.name}"
    return None

