# Сетка D11 в оригинале: все полноразмерные .bmp из GT/Pictures, кроме миниатюр *_m.bmp
# (полный кадр — animals.bmp, shapes1.bmp, pic_l.bmp и т.д.). Порядок: сначала pic_* (как в
# установке), затем остальные по имени. Иначе — файл GT/a_training_pictures.txt (по одному
# имени файла в строке, UTF-8), чтобы совпасть с порядком в D11.dll.
D11_PIC_PREFIX = "pic_"
D11_KNOWN_PIC_ORDER = (
    "pic_l.bmp",
    "pic_d.bmp",
    "pic_lR.bmp",
)


def _sort_pic_prefixed(names: list[str]) -> list[str]:
    order = {n.lower(): i for i, n in enumerate(D11_KNOWN_PIC_ORDER)}
    return sorted(names, key=lambda n: (order.get(n.lower(), 1000), n.lower()))


def list_a_training_pictures():
    """Список картинок сетки А-Тренинга: см. комментарий к D11_PIC_PREFIX / манифест."""
    pic_dir = legacy_pictures_dir()
    if not pic_dir:
        return []
    pic_root = pic_dir.resolve()
    manifest = LEGACY_GT / "a_training_pictures.txt"
    if manifest.is_file():
        ordered: list[str] = []
        seen: set[str] = set()
        text = manifest.read_text(encoding="utf-8", errors="ignore")
        for line in text.splitlines():
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            base = Path(line.replace("\\", "/")).name
            if not base or base in (".", "..") or ".." in base:
                continue
            target = (pic_root / base).resolve()
            try:
                target.relative_to(pic_root)
            except ValueError:
                continue
            if not target.is_file() or target.suffix.lower() != ".bmp":
                continue
            key = target.name
            if key.lower() in seen:
                continue
            seen.add(key.lower())
            ordered.append(key)
        return ordered

    pic_pref: list[str] = []
    other: list[str] = []
    for p in pic_dir.iterdir():
        if not p.is_file():
            continue
        if p.suffix.lower() != ".bmp":
            continue
        if p.name.lower().endswith("_m.bmp"):
            continue
        if p.name.lower().startswith(D11_PIC_PREFIX):
            pic_pref.append(p.name)
        else:
            other.append(p.name)
    return _sort_pic_prefixed(pic_pref) + sorted(other, key=lambda n: n.lower())

