"""Изображения А-Тренинга из ресурсов GT/D11.dll (JPEG PICT1…PICT12), как в оригинале."""

from __future__ import annotations

import re
from pathlib import Path


def _resource_entry_name(entry) -> str | None:
    n = entry.name
    if n is None:
        return None
    if hasattr(n, "string"):
        return n.string.decode("utf-8", errors="replace")
    return str(n)


def ensure_d11_training_images(legacy_gt: Path, static_root: Path) -> tuple[bool, str | None]:
    """Пишет static/d11_embed/full_01.jpg … full_12.jpg и thumb_01… из D11.dll."""
    dll = legacy_gt / "D11.dll"
    if not dll.is_file():
        return False, "Не найден файл GT/D11.dll."

    dest = static_root / "d11_embed"
    dest.mkdir(parents=True, exist_ok=True)
    sig_path = dest / ".extracted_sig"
    try:
        st = dll.stat()
        sig = f"{int(st.st_mtime)}|{st.st_size}"
        if sig_path.is_file() and sig_path.read_text(encoding="utf-8").strip() == sig:
            if (dest / "full_12.jpg").is_file() and (dest / "thumb_12.jpg").is_file():
                return True, None
    except OSError:
        pass

    try:
        import pefile
    except ImportError:
        return False, "Нужен пакет pefile (pip install pefile)."

    try:
        pe = pefile.PE(str(dll))
        jpeg_root = None
        for e1 in pe.DIRECTORY_ENTRY_RESOURCE.entries:
            if _resource_entry_name(e1) == "JPEG":
                jpeg_root = e1
                break
        if jpeg_root is None:
            return False, "В D11.dll нет каталога ресурсов JPEG."

        by_name: dict[str, bytes] = {}
        for e2 in jpeg_root.directory.entries:
            name = _resource_entry_name(e2)
            if not name or not e2.struct.DataIsDirectory:
                continue
            leaf = e2.directory.entries[0]
            off = leaf.data.struct.OffsetToData
            sz = leaf.data.struct.Size
            by_name[name] = pe.get_data(off, sz)

        for i in range(1, 13):
            key = f"PICT{i}"
            main = by_name.get(key)
            if not main or main[:2] != b"\xff\xd8":
                return False, f"В D11.dll отсутствует или повреждён ресурс {key}."
            thumb_key = f"PICT{i}_1"
            th = by_name.get(thumb_key)
            if not th or th[:2] != b"\xff\xd8":
                th = main
            (dest / f"full_{i:02d}.jpg").write_bytes(main)
            (dest / f"thumb_{i:02d}.jpg").write_bytes(th)

        sig_path.write_text(sig, encoding="utf-8")
        return True, None
    except Exception as exc:
        return False, f"Ошибка разбора D11.dll: {exc}"


def pict_index_from_name(name: str) -> int | None:
    m = re.match(r"^PICT(\d+)$", name.strip(), re.I)
    if not m:
        return None
    n = int(m.group(1))
    return n if 1 <= n <= 12 else None

