def d21_digit_bounds(size: int):
    """Диапазон чисел по «размеру» (как D21Size в оригинале): 1→1–9, 2→10–99, …"""
    s = max(1, min(4, int(size)))
    if s == 1:
        return 1, 9
    lo = 10 ** (s - 1)
    hi = 10**s - 1
    return lo, hi


def d21_generate_round(size: int, interval: int):
    """Случайный обратный отсчёт: start → … → end, вычитая фиксированный step ∈ [1..interval]."""
    lo, hi = d21_digit_bounds(size)
    imax = max(1, min(9, int(interval)))
    step = random.randint(1, imax)
    k = random.randint(8, 22)
    end_hi = hi - k * step
    if end_hi < lo:
        return d21_generate_round(size, interval)
    end = random.randint(lo, end_hi)
    start = end + k * step
    if start > hi:
        k2 = (hi - end) // step
        if k2 < 5:
            return d21_generate_round(size, interval)
        start = end + k2 * step
    return start, end, step


def d21_module_neighbors(db, module_id):
    ordered_modules = db.execute(
