        SELECT id, dll_name FROM modules
        WHERE dll_name LIKE 'D%.dll'
        """
    ).fetchall()
    ordered_modules = sorted(ordered_modules, key=lambda m: dll_sort_key(m["dll_name"]))
    ids = [m["id"] for m in ordered_modules]
    prev_id = next_id = None
    if module_id in ids:
        idx = ids.index(module_id)
        if idx > 0:
            prev_id = ids[idx - 1]
        if idx < len(ids) - 1:
            next_id = ids[idx + 1]
    return prev_id, next_id

