@login_required
def d21_module(module_id):
    """Упражнение «Отсчёт» (D21.dll): обратный счёт с заданным шагом, настройки Size / Interval."""
    db = get_db()
    module = db.execute(
        "SELECT id, title, description, dll_name FROM modules WHERE id = ?",
        (module_id,),
    ).fetchone()
    if not module:
        flash("Модуль не найден.")
        return redirect(url_for("dashboard"))
    if module["dll_name"] != "D21.dll":
        return redirect(url_for("module_view", module_id=module_id))

    module_rules = db.execute(
        "SELECT rule_text FROM module_rules WHERE lower(dll_name) = lower(?)",
        (module["dll_name"],),
    ).fetchone()
    prev_module_id, next_module_id = d21_module_neighbors(db, module_id)

    placeholder = db.execute(
        """
        SELECT id FROM exercises
        WHERE module_id = ?
        ORDER BY id LIMIT 1
        """,
        (module_id,),
    ).fetchone()

    prefs = session.get("d21_prefs") or {"size": 2, "interval": 3}
    state = session.get("d21")
    if state and int(state.get("module_id", 0)) != module_id:
        session.pop("d21", None)
        state = None

    if request.method == "POST":
        act = (request.form.get("d21_action") or "").strip()
        if act == "mark_done":
            if placeholder:
                db.execute(
                    """
                    INSERT INTO progress (user_id, exercise_id, completed, score)
                    VALUES (?, ?, 1, 100)
                    ON CONFLICT(user_id, exercise_id)
                    DO UPDATE SET completed = 1, score = 100
                    """,
                    (session["user_id"], placeholder["id"]),
                )
                db.commit()
            flash("Сессия «Отсчёт» отмечена как выполненная.")
            return redirect(url_for("d21_module", module_id=module_id))
        if act == "reset":
            session.pop("d21", None)
            session.pop("d21_last", None)
            flash("Сброшено. Задайте настройки и начните новый отсчёт.")
            return redirect(url_for("d21_module", module_id=module_id))
        if act == "start":
            try:
                size = int(request.form.get("d21_size", prefs["size"]))
                interval = int(request.form.get("d21_interval", prefs["interval"]))
            except (TypeError, ValueError):
                flash("Укажите целые числа в настройках.")
                return redirect(url_for("d21_module", module_id=module_id))
            size = max(1, min(4, size))
            interval = max(1, min(9, interval))
            session["d21_prefs"] = {"size": size, "interval": interval}
            session.pop("d21_last", None)
            start, end, step = d21_generate_round(size, interval)
            session["d21"] = {
                "module_id": module_id,
                "size": size,
                "interval": interval,
                "start": start,
                "end": end,
                "step": step,
                "current": start,
                "faults": 0,
                "t0": time.time(),
            }
            return redirect(url_for("d21_module", module_id=module_id))
        if act == "step" and state:
            raw = (request.form.get("d21_answer") or "").strip()
            try:
                ans = int(raw)
            except ValueError:
                flash("Введите следующее целое число (результат вычитания).")
                return redirect(url_for("d21_module", module_id=module_id))
            expected = state["current"] - state["step"]
            if ans != expected:
                state["faults"] = int(state.get("faults", 0)) + 1
                session["d21"] = state
                flash(f"Неверно. После {state['current']} с шагом {state['step']} должно быть {expected}.")
                return redirect(url_for("d21_module", module_id=module_id))
            state["current"] = expected
            session["d21"] = state
            if expected == state["end"]:
                elapsed = max(0, int(time.time() - float(state["t0"])))
                faults = int(state.get("faults", 0))
                score = max(60, 100 - faults * 12)
                session["d21_last"] = {
                    "sec": elapsed,
                    "faults": faults,
                    "start": state["start"],
                    "end": state["end"],
                    "step": state["step"],
                    "score": score,
                }
                session.pop("d21", None)
                flash("Серия отсчёта завершена.")
            return redirect(url_for("d21_module", module_id=module_id))

    d21_done = session.get("d21_last")
    return render_template(
        "d21.html",
        module=module,
        rule_text=module_rules["rule_text"] if module_rules else "",
        prev_module_id=prev_module_id,
        next_module_id=next_module_id,
        prefs=prefs,
        state=state,
        d21_done=d21_done,
    )


