            continue
        if k_hi >= 5:
            k = random.randint(5, k_hi)
        else:
            k = random.randint(3, k_hi)
        end_max = hi - k * step
        if end_max < lo:
            continue
        end = random.randint(lo, end_max)
        start = end + k * step
        if lo <= end < start <= hi:
            return start, end, step
    step = 1
    end = lo
    start = min(hi, end + max(3, min(8, span)))
    if start > end:
        return start, end, step
    return hi, lo, 1

