def d21_build_sequence(start: int, end: int, step: int) -> list[int]:
    """Цепочка чисел для автопоказа: start, start-step, …, end."""
    out = []
    x = int(start)
    end = int(end)
    step = int(step)
    while x >= end:
        out.append(x)
        if x == end:
            break
        x -= step
    return out


