</div>
{% endif %}

{% if state %}
<div class="card">
  <h3>Автоматический отсчёт</h3>
  <p class="d21-meta">Следите за числами и проговаривайте про себя следующее (от большего к меньшему, шаг <b>{{ state.step }}</b>). Ввод с клавиатуры не нужен — как в оригинальной программе.</p>
  <p class="d21-meta">Цель — дойти до <b>{{ state.end }}</b>. Пауза между сменой чисел: <b>{{ state.pause_ms }}</b> мс.</p>
  <div id="d21-display" class="d21-display" aria-live="polite">—</div>
  <div class="d21-controls">
    <button type="button" id="d21-btn-start">Пуск</button>
    <button type="button" id="d21-btn-pause" disabled>Пауза</button>
    <button type="button" id="d21-btn-stop" disabled>Стоп</button>
  </div>
  <form id="d21-finish-form" method="post" style="display:none;">
    <input type="hidden" name="d21_action" value="playback_done">
    <input type="hidden" name="duration_sec" id="d21-dur" value="0">
  </form>
  <form method="post" style="margin-top:16px;">
    <input type="hidden" name="d21_action" value="reset">
    <button type="submit" style="width:auto;background:#6b7280;">Новая серия (сброс настроек показа)</button>
  </form>
</div>
<script>
(function () {
  var seq = {{ state.sequence | tojson }};
  var pause = {{ state.pause_ms | int }};
  var el = document.getElementById("d21-display");
  var form = document.getElementById("d21-finish-form");
  var durInput = document.getElementById("d21-dur");
  var btnStart = document.getElementById("d21-btn-start");
  var btnPause = document.getElementById("d21-btn-pause");
  var btnStop = document.getElementById("d21-btn-stop");
  var pos = 0;
  var timer = null;
  var tStart = 0;
  var running = false;

  function finish(sec) {
    running = false;
    if (timer) { clearInterval(timer); timer = null; }
    btnStart.disabled = false;
    btnPause.disabled = true;
    btnStop.disabled = true;
    durInput.value = String(Math.max(0, sec));
    form.submit();
  }

  function tick() {
    if (pos >= seq.length) {
      var sec = Math.round((Date.now() - tStart) / 1000);
      finish(sec);
      return;
    }
    el.textContent = String(seq[pos]);
    pos++;
  }

  function startRun() {
    if (running && timer) return;
    if (!running) {
      pos = 0;
      tStart = Date.now();
      el.textContent = "…";
    }
    running = true;
    btnStart.disabled = true;
    btnPause.disabled = false;
    btnStop.disabled = false;
    tick();
    if (timer) clearInterval(timer);
    timer = setInterval(tick, pause);
  }

  function pauseRun() {
    if (!timer) return;
    clearInterval(timer);
    timer = null;
    btnStart.disabled = false;
    btnPause.disabled = true;
  }

  function stopRun() {
    if (timer) { clearInterval(timer); timer = null; }
    running = false;
    pos = 0;
    el.textContent = "—";
    btnStart.disabled = false;
    btnPause.disabled = true;
    btnStop.disabled = true;
  }

  btnStart.addEventListener("click", function () {
    if (timer === null && pos === 0 && !running) {
      startRun();
    } else if (!timer && running) {
      startRun();
    } else if (!timer && pos > 0) {
      startRun();
    }
  });
  btnPause.addEventListener("click", pauseRun);
  btnStop.addEventListener("click", stopRun);
})();
</script>
