        return redirect(url_for("module_view", module_id=module_id))

    module_rules = db.execute(
        "SELECT rule_text FROM module_rules WHERE lower(dll_name) = lower(?)",
        (module["dll_name"],),
    ).fetchone()
    prev_module_id, next_module_id = d21_module_neighbors(db, module_id)

    placeholder = db.execute(
        """
        SELECT id FROM exercises
        WHERE module_id = ?
        ORDER BY id LIMIT 1
        """,
        (module_id,),
    ).fetchone()

    _d64_def = {"n": 5, "order": "asc", "show_dot": True, "font_pt": 20}
    prefs = {**_d64_def, **(session.get("d64_prefs") or {})}
    game = session.get("d64")
    if game and int(game.get("module_id", 0)) != module_id:
        session.pop("d64", None)
        game = None
    if game and (
        not game.get("cells")
        or len(game["cells"]) != game.get("n", 0) ** 2
        or not game.get("sequence")
    ):
        session.pop("d64", None)
        game = None

    if request.method == "POST":
        act = (request.form.get("d64_action") or "").strip()
        if act == "mark_done":
            scr = 100
            last = session.get("d64_last")
            if last and last.get("score") is not None:
                scr = int(last["score"])
            if placeholder:
                db.execute(
                    """
                    INSERT INTO progress (user_id, exercise_id, completed, score)
                    VALUES (?, ?, 1, ?)
                    ON CONFLICT(user_id, exercise_id)
                    DO UPDATE SET completed = 1, score = excluded.score
                    """,
                    (session["user_id"], placeholder["id"], scr),
                )
                db.commit()
            flash("Упражнение «Шульте» отмечено как выполненное.")
            return redirect(url_for("d64_module", module_id=module_id))
        if act == "reset":
            session.pop("d64", None)
            session.pop("d64_last", None)
            flash("Таблица сброшена.")
            return redirect(url_for("d64_module", module_id=module_id))
        if act == "start":
            try:
                n = int(request.form.get("d64_n", prefs["n"]))
                font_pt = int(request.form.get("d64_font_pt", prefs["font_pt"]))
            except (TypeError, ValueError):
                flash("Проверьте настройки таблицы.")
                return redirect(url_for("d64_module", module_id=module_id))
            order = (request.form.get("d64_order") or "asc").strip().lower()
            show_dot = request.form.get("d64_show_dot") == "1"
