D34_WORDS_A = "дом лес снег река поле ночь вода".split()
D34_WORDS_B = "стол стул окно дверь книга ручка бумага".split()


def d34_default_prefs():
    return {
        "mode_total": True,
        "use_pict": True,
        "min_n": 4,
        "max_n": 12,
        "show_sec": 0.5,
        "session_min": 3,
    }


def d34_finalize_stats(stats: dict) -> dict:
    ok = int(stats.get("ok", 0))
    fail = int(stats.get("fail", 0))
    tot = ok + fail
    if tot == 0:
        score = 72
    else:
        score = max(60, min(100, int(round(100 * ok / tot))))
    return {"ok": ok, "fail": fail, "score": score}


def d34_generate_round(prefs: dict, pict_pair: tuple[str, str] | None):
    """Один показ: элементы для вспышки и правильный ответ (только на сервере в сессии)."""
    min_n = int(prefs["min_n"])
    max_n = int(prefs["max_n"])
    n = random.randint(min_n, max_n)
    mode_total = bool(prefs.get("mode_total", True))
    use_pict = bool(prefs.get("use_pict", True))
    items = []
    instruction = ""
    samples = []

    if mode_total:
        if use_pict and pict_pair:
            u1, u2 = pict_pair
            for _ in range(n):
                items.append({"t": "img", "src": random.choice((u1, u2))})
            instruction = "Укажите общее количество показанных картинок."
        elif use_pict:
            palette = ["#2563eb", "#dc2626", "#16a34a", "#ca8a04"]
            for _ in range(n):
                items.append({"t": "color", "c": random.choice(palette)})
            instruction = "Укажите общее число цветных меток."
        else:
            pool = D34_WORDS_A + D34_WORDS_B
            for _ in range(n):
                items.append({"t": "word", "w": random.choice(pool)})
            instruction = "Укажите общее число слов на экране."
        correct = n
    else:
        if use_pict and pict_pair:
            u1, u2 = pict_pair
            correct = random.randint(0, n)
            rest = n - correct
            items = [{"t": "img", "src": u1}] * correct + [{"t": "img", "src": u2}] * rest
            random.shuffle(items)
            instruction = (
                "Считайте только картинки первого типа (как на левом образце). "
                "Второй тип — справа."
            )
            samples = [
                {"src": u1, "cap": "Считать"},
                {"src": u2, "cap": "Не считать"},
            ]
        elif use_pict:
            target_c, other_c = "#2563eb", "#dc2626"
            correct = random.randint(0, n)
            items = [{"t": "color", "c": target_c}] * correct + [
                {"t": "color", "c": other_c}
            ] * (n - correct)
            random.shuffle(items)
            instruction = "Считайте только синие квадраты (красные не учитывайте)."
        else:
            wa = random.choice(D34_WORDS_A)
            wb = random.choice(D34_WORDS_B)
            if wa == wb:
                wb = random.choice([x for x in D34_WORDS_B if x != wa] or D34_WORDS_B)
            correct = random.randint(0, n)
            items = [{"t": "word", "w": wa}] * correct + [{"t": "word", "w": wb}] * (
                n - correct
            )
            random.shuffle(items)
            instruction = f"Считайте только слова «{wa}». Слова «{wb}» не учитывайте."

    return {
        "items": items,
        "correct": int(correct),
        "instruction": instruction,
        "samples": samples,
    }


