@app.route("/d34/<int:module_id>", methods=["GET", "POST"])
@login_required
def d34_module(module_id):
    """Фотопамять / фотооценка (D34.dll): короткий показ группы, ответ — число."""
    db = get_db()
    module = db.execute(
        "SELECT id, title, description, dll_name FROM modules WHERE id = ?",
        (module_id,),
    ).fetchone()
    if not module:
        flash("Модуль не найден.")
        return redirect(url_for("dashboard"))
    if module["dll_name"] != "D34.dll":
        return redirect(url_for("module_view", module_id=module_id))

    module_rules = db.execute(
        "SELECT rule_text FROM module_rules WHERE lower(dll_name) = lower(?)",
        (module["dll_name"],),
    ).fetchone()
    prev_module_id, next_module_id = d21_module_neighbors(db, module_id)

    placeholder = db.execute(
        """
        SELECT id FROM exercises
        WHERE module_id = ?
        ORDER BY id LIMIT 1
        """,
        (module_id,),
    ).fetchone()

    tiles_ok, _tiles_err = ensure_d11_training_images(LEGACY_GT, BASE_DIR / "static")

    def pict_pair_urls():
        if not tiles_ok:
            return None
        a, b = random.sample(range(1, 13), 2)
        return (
            url_for("static", filename=f"d11_embed/thumb_{a:02d}.jpg"),
            url_for("static", filename=f"d11_embed/thumb_{b:02d}.jpg"),
        )

    prefs_default = d34_default_prefs()
    prefs = {**prefs_default, **(session.get("d34_prefs") or {})}
    st = session.get("d34")
    if st and int(st.get("module_id", 0)) != module_id:
        session.pop("d34", None)
        st = None
    now = time.time()
    if st and now >= float(st.get("ends_at", 0)):
        session["d34_last"] = d34_finalize_stats(st.get("stats") or {})
        session.pop("d34", None)
        st = None
        flash("Время серии «Фото» истекло. Можно начать новую.")

    if request.method == "POST":
        act = (request.form.get("d34_action") or "").strip()
        if act == "mark_done":
            scr = 100
            last = session.get("d34_last")
            if last and last.get("score") is not None:
                scr = int(last["score"])
            if placeholder:
                db.execute(
                    """
                    INSERT INTO progress (user_id, exercise_id, completed, score)
                    VALUES (?, ?, 1, ?)
                    ON CONFLICT(user_id, exercise_id)
                    DO UPDATE SET completed = 1, score = excluded.score
                    """,
                    (session["user_id"], placeholder["id"], scr),
                )
                db.commit()
            flash("Упражнение «Фото» отмечено как выполненное.")
            return redirect(url_for("d34_module", module_id=module_id))
        if act == "stop":
            if st:
                session["d34_last"] = d34_finalize_stats(st.get("stats") or {})
            session.pop("d34", None)
            flash("Серия остановлена.")
            return redirect(url_for("d34_module", module_id=module_id))
        if act == "start":
            try:
                min_n = int(request.form.get("d34_min", prefs["min_n"]))
                max_n = int(request.form.get("d34_max", prefs["max_n"]))
            except (TypeError, ValueError):
                flash("Проверьте числа «от / до» для размера группы.")
                return redirect(url_for("d34_module", module_id=module_id))
            min_n = max(2, min(28, min_n))
            max_n = max(min_n, min(28, max_n))
            try:
                show_sec = float(
                    (request.form.get("d34_show") or str(prefs["show_sec"])).replace(
                        ",", "."
                    )
                )
            except ValueError:
                flash("Некорректное время показа.")
                return redirect(url_for("d34_module", module_id=module_id))
            show_sec = max(0.1, min(2.0, show_sec))
            try:
                session_min = int(
                    request.form.get("d34_session_min", prefs["session_min"])
                )
            except (TypeError, ValueError):
                session_min = prefs_default["session_min"]
            session_min = max(1, min(15, session_min))
            mode_total = request.form.get("d34_count_mode") != "group"
            use_pict = request.form.get("d34_element_kind") != "words"
            session["d34_prefs"] = {
                "mode_total": mode_total,
                "use_pict": use_pict,
                "min_n": min_n,
                "max_n": max_n,
                "show_sec": show_sec,
                "session_min": session_min,
            }
            prefs = session["d34_prefs"]
            pair = pict_pair_urls() if prefs["use_pict"] else None
            rnd = d34_generate_round(prefs, pair)
            session["d34"] = {
                "module_id": module_id,
                "ends_at": now + session_min * 60,
                "prefs": prefs,
                "stats": {"ok": 0, "fail": 0},
                "round": rnd,
                "feedback": None,
            }
            session.pop("d34_last", None)
            return redirect(url_for("d34_module", module_id=module_id))
        if act == "next_round" and st:
            if now >= float(st["ends_at"]):
                session["d34_last"] = d34_finalize_stats(st.get("stats") or {})
                session.pop("d34", None)
                flash("Время серии истекло.")
                return redirect(url_for("d34_module", module_id=module_id))
            pr = st.get("prefs") or prefs
            pair = pict_pair_urls() if pr.get("use_pict") else None
            st["round"] = d34_generate_round(pr, pair)
            st["feedback"] = None
            session["d34"] = st
            return redirect(url_for("d34_module", module_id=module_id))
        if act == "answer" and st and st.get("round"):
            if now >= float(st["ends_at"]):
                session["d34_last"] = d34_finalize_stats(st.get("stats") or {})
                session.pop("d34", None)
                flash("Время серии истекло.")
                return redirect(url_for("d34_module", module_id=module_id))
            raw = (request.form.get("answer") or "").strip()
            try:
                guess = int(raw)
            except ValueError:
                flash("Введите целое число — сколько элементов вы насчитали.")
                return redirect(url_for("d34_module", module_id=module_id))
            if guess < 0 or guess > 80:
                flash("Некорректный ответ.")
                return redirect(url_for("d34_module", module_id=module_id))
            correct = int(st["round"]["correct"])
            ok = guess == correct
            st["stats"]["ok" if ok else "fail"] = int(
                st["stats"].get("ok" if ok else "fail", 0)
            ) + 1
            st["feedback"] = {"ok": ok, "correct": correct, "guess": guess}
            st["round"] = None
            session["d34"] = st
            if ok:
                flash("Верно.")
            else:
                flash(f"Неверно. Было: {correct} (ваш ответ: {guess}).")
            return redirect(url_for("d34_module", module_id=module_id))

    st = session.get("d34")
    if st and time.time() >= float(st.get("ends_at", 0)):
        session["d34_last"] = d34_finalize_stats(st.get("stats") or {})
        session.pop("d34", None)
        st = None
        flash("Время серии «Фото» истекло.")

    d34_done = session.get("d34_last")
    time_left_sec = 0
    round_view = None
    flash_ms = int(round(float(prefs.get("show_sec", 0.5)) * 1000))
    feedback = None
    stats_view = None
    if st:
        time_left_sec = max(0, int(float(st["ends_at"]) - time.time()))
        flash_ms = int(round(float(st["prefs"].get("show_sec", 0.5)) * 1000))
        stats_view = st.get("stats")
        feedback = st.get("feedback")
        r = st.get("round")
        if r:
            round_view = {
                "instruction": r["instruction"],
                "items": r["items"],
                "samples": r.get("samples") or [],
                "flash_ms": flash_ms,
            }

    return render_template(
        "d34.html",
        module=module,
        rule_text=module_rules["rule_text"] if module_rules else "",
        prev_module_id=prev_module_id,
        next_module_id=next_module_id,
        prefs=prefs,
        tiles_ok=tiles_ok,
        st_active=bool(st),
        time_left_sec=time_left_sec,
        round_view=round_view,
        feedback=feedback,
        stats=stats_view,
        d34_done=d34_done,
    )


