        const s = document.createElement('span');
        s.className = 'd34-cell-word';
        s.textContent = it.w;
        grid.appendChild(s);
      }
    });
  }
  btn.addEventListener('click', function () {
    btn.style.display = 'none';
    grid.style.display = 'flex';
    renderItems();
    setTimeout(function () {
      grid.style.display = 'none';
      form.style.display = 'block';
      var inp = document.getElementById('d34-answer-input');
      if (inp) { inp.focus(); }
    }, flashMs);
  });
})();
</script>
