    }


def d34_scatter_positions(n: int, rng: random.Random) -> list[tuple[float, float]]:
    """Случайные позиции в процентах поля — как «сыпь» иконок в оригинальном поле."""
    out: list[tuple[float, float]] = []
    for _ in range(n):
        placed = False
        for _try in range(100):
            x = rng.uniform(8.0, 92.0)
            y = rng.uniform(10.0, 90.0)
            if all((x - ox) ** 2 + (y - oy) ** 2 >= 30.25 for ox, oy in out):
                out.append((x, y))
                placed = True
                break
        if not placed:
            out.append((rng.uniform(14.0, 86.0), rng.uniform(14.0, 86.0)))
    return out

