{% extends "base.html" %}
{% block title %}{{ module["title"] }} — Глобал Т.Э.М.П.{% endblock %}
{% block content %}
<style>
  .d34-hud { font-size: 11pt; margin: 10px 0; color: #003399; }
  .d34-timer-wrap {
    margin: 8px 0 12px 0;
    max-width: 420px;
    font-family: Verdana, Arial, sans-serif;
    font-size: 9pt;
    color: #374151;
  }
  .d34-timer-bar {
    height: 8px;
    background: #e5e7eb;
    border: 1px solid #c2cdd6;
    margin-top: 4px;
    overflow: hidden;
  }
  .d34-timer-fill {
    height: 100%;
    background: linear-gradient(90deg, #93c5fd, #003399);
    transition: width 0.3s ease;
  }
  .d34-settings label { display: block; font-size: 9pt; color: #003399; margin-bottom: 4px; }
  .d34-settings .row { display: flex; flex-wrap: wrap; gap: 16px; align-items: flex-end; margin: 12px 0; }
  .d34-settings input[type="number"], .d34-settings select { width: 130px; padding: 8px; margin: 0 0 8px 0; }
  .d34-settings select.wide { width: 220px; }
  .d34-settings button.inline, .d34-actions button.inline { width: auto !important; margin: 4px 8px 8px 0 !important; display: inline-block; }
  .d34-samples { display: flex; gap: 20px; flex-wrap: wrap; margin: 12px 0; align-items: flex-end; }
  .d34-samples figure { margin: 0; text-align: center; font-size: 9pt; color: #003399; }
  .d34-samples img { width: 72px; height: 72px; object-fit: cover; border: 1px solid #c2cdd6; }
  .d34-field-wrap { margin: 12px 0; }
  .d34-field {
    display: none;
    position: relative;
    width: 100%;
    max-width: 640px;
    height: 300px;
    margin: 0 auto;
    background: #f3f4f6;
    border: 2px solid #9ca3af;
    overflow: hidden;
    box-sizing: border-box;
  }
  .d34-field .d34-el {
    position: absolute;
    transform: translate(-50%, -50%);
    margin: 0;
  }
  .d34-cell-img { width: 48px; height: 48px; object-fit: cover; border: 1px solid #6b7280; display: block; }
  .d34-cell-color { width: 40px; height: 40px; border: 1px solid #4b5563; }
  .d34-cell-word {
    padding: 4px 8px;
    border: 1px solid #6b7280;
    background: #fff;
    font-size: 13pt;
    color: #111827;
    white-space: nowrap;
  }
  .d34-font-times .d34-cell-word { font-family: "Times New Roman", Times, serif; }
  .d34-font-arial .d34-cell-word { font-family: Verdana, Arial, sans-serif; }
  .d34-font-courier .d34-cell-word { font-family: "Courier New", Courier, monospace; }
  .d34-wait { font-size: 10pt; color: #6b7280; margin: 8px 0; min-height: 1.2em; }
  .d34-done { border: 1px solid #c2cdd6; background: #f3fdf3; padding: 12px; margin: 12px 0; }
  .d34-reveal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(255,255,255,0.92);
    z-index: 2000;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    font-family: Verdana, Arial, sans-serif;
  }
  .d34-reveal-overlay .big { font-size: 42pt; font-weight: 700; color: #003399; }
  .d34-reveal-overlay .sub { font-size: 14pt; color: #4b5563; margin-top: 12px; }
  .d34-reveal-ok .big { color: #15803d; }
  .d34-reveal-bad .big { color: #b91c1c; }
</style>

<h2>{{ module["title"] }}</h2>
