    Время показа <strong>всей группы</strong> на поле: {{ (round_view.flash_ms / 1000)|round(2) }} с
    (параметр Show в D34, 0,1–2 с). Далее вводите число и нажимайте Enter.
  </p>
  <p class="d34-wait" id="d34-wait-msg">Приготовьтесь — поле появится автоматически…</p>
  <button type="button" id="d34-replay-btn" class="inline" style="width:auto !important;display:none;background:#6b7280;">Показать поле ещё раз</button>
  <div class="d34-field-wrap">
    <div id="d34-flash" class="d34-field d34-font-{{ round_view.word_font }}" aria-live="polite"></div>
  </div>
  <form id="d34-answer-form" method="post" style="display:none;">
    <input type="hidden" name="d34_action" value="answer">
    <label for="d34-answer-input">Сколько элементов (по условию выше)?</label>
    <input type="number" id="d34-answer-input" name="answer" min="0" max="80" required autocomplete="off" style="max-width:220px;">
    <button type="submit" class="inline" style="width:auto !important;">Ответить (Enter)</button>
  </form>
</div>
<script>
(function () {
  const items = {{ round_view.elements|tojson }};
  const flashMs = {{ round_view.flash_ms|int }};
  const field = document.getElementById('d34-flash');
  const form = document.getElementById('d34-answer-form');
  const waitEl = document.getElementById('d34-wait-msg');
  const replayBtn = document.getElementById('d34-replay-btn');
  const samplesRow = document.getElementById('d34-samples-row');
  const fontClass = {{ round_view.word_font|tojson }};

  function renderField() {
    field.innerHTML = '';
    items.forEach(function (it) {
      const wrap = document.createElement('div');
      wrap.className = 'd34-el';
      wrap.style.left = it.xp + '%';
      wrap.style.top = it.yp + '%';
      if (it.t === 'img') {
        const img = document.createElement('img');
        img.src = it.src;
        img.alt = '';
        img.className = 'd34-cell-img';
        wrap.appendChild(img);
      } else if (it.t === 'color') {
        const d = document.createElement('div');
        d.className = 'd34-cell-color';
        d.style.background = it.c;
        wrap.appendChild(d);
      } else {
        const s = document.createElement('span');
        s.className = 'd34-cell-word';
        s.textContent = it.w;
        wrap.appendChild(s);
      }
      field.appendChild(wrap);
    });
  }

  function runFlash() {
    if (samplesRow) { samplesRow.style.opacity = '0.35'; }
    waitEl.textContent = '';
    field.style.display = 'block';
    renderField();
    setTimeout(function () {
      field.style.display = 'none';
      field.innerHTML = '';
      if (samplesRow) { samplesRow.style.opacity = '1'; }
      form.style.display = 'block';
      replayBtn.style.display = 'inline-block';
      var inp = document.getElementById('d34-answer-input');
      if (inp) { inp.focus(); }
    }, flashMs);
  }

  setTimeout(runFlash, 750);
  replayBtn.addEventListener('click', function () {
    form.style.display = 'none';
    waitEl.textContent = 'Повторный показ…';
    setTimeout(runFlash, 200);
  });

  var ans = document.getElementById('d34-answer-input');
  if (ans) {
    ans.addEventListener('keydown', function (e) {
      if (e.key === 'Enter') { e.preventDefault(); form.requestSubmit(); }
    });
  }
})();
</script>
